from agentpulse.client.types import ConnectionState, Limits, Session

logger = logging.getLogger(__name__)


def _midnight_local() -> float:
    """Today's local midnight as Unix epoch seconds."""
    return datetime.now().replace(hour=0, minute=0, second=0, microsecond=0).timestamp()


class AsyncAgentPulseClient:
    """Async streaming client over the AgentPulse v2 surface."""

